changeSet.sql:
GRANT USAGE ON SCHEMA audit TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA audit GRANT USAGE ON SEQUENCES TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA audit GRANT EXECUTE ON FUNCTIONS TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA audit GRANT SELECT,INSERT,UPDATE ON TABLES TO ${app-username};

GRANT USAGE ON SCHEMA audit TO ${viewer-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA audit GRANT EXECUTE ON FUNCTIONS TO ${viewer-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA audit GRANT SELECT ON TABLES TO ${viewer-username};
